mapper.select:
/* ====== cmn.login.selectLogin =========*/ SELECT '' || COUNT(1) AS ID_CNT ,'' || SUM(DECODE(PASS, #{pass, jdbcType=VARCHAR} , 1, 0)) PASS_CNT ,MAX(A.USR_NM) USR_NM ,MAX(A.USR_ID) USR_ID ,MAX(USG_END_DT) USG_END_DT ,MAX(MSK_AUTH_YN) MSK_AUTH_YN ,MAX(A.ORGN_ID) ORGN_ID ,MAX(B.ORGN_NM) ORGN_NM ,MAX(B.TYPE_CD) TYPE_CD ,MAX(B.ORGN_LVL_CD) ORGN_LVL_CD ,MAX(B.LOGIS_CNTER_YN) LOGIS_CNTER_YN ,MAX('' || A.MNGR_RULE) MNGR_RULE ,MAX(B.TYPE_DTL_CD1) TYPE_DTL_CD1 FROM CMN_USR_MST A, ORG_ORGN_INFO_MST B WHERE A.USR_ID = UPPER(#{usrId, jdbcType=VARCHAR}) AND A.ORGN_ID = B.ORGN_ID(+) AND A.USG_YN = 'Y'
AND ( A.USG_STRT_DT IS NULL OR TO_CHAR(SYSDATE,'YYYYMMDD') >= A.USG_STRT_DT) AND ( A.USG_END_DT IS NULL OR TO_CHAR(SYSDATE,'YYYYMMDD') <= A.USG_END_DT)
and 1 =1

mapper.insert:
/* ====== cmn.login.insertLog =========*/

  INSERT INTO CMN_USR_CNNCT_LOG_HST
  (
     LOG_DTTM,
     IP_INFO,
     MAC_ADDR,
     SUCC_YN,
     REGST_PRGM,
     REGSTST_ID,
     REGST_DTTM  ,
     USR_ID
  )
  VALUES
  (
      sysdate
     ,#{ipInfo     , jdbcType=VARCHAR}
     ,#{macAddr    , jdbcType=VARCHAR}
     ,#{succYn     , jdbcType=VARCHAR}
     ,#{regstPrgm  , jdbcType=VARCHAR}
     ,substrb(#{usrId},1,10)
     ,sysdate
     ,substrb(#{usrId},1,10)
  )

mapper.update:
	/* ====== cmn.login.updateUserLastLoginDt =========*/
	UPDATE	CMN_USR_MST
  	SET		LAST_LOGIN_DT = SYSDATE
  	WHERE	USR_ID  = #{usrId, jdbcType=VARCHAR}

/* ====== cmn.login.updateUserPassErrNum =========*/
UPDATE	CMN_USR_MST
SET 	PASS_ERR_NUM = decode( #{loginResult, jdbcType=VARCHAR} , 'SUCCESS',0, 'WRONG_PASSWORD', nvl(PASS_ERR_NUM,0) + 1 , PASS_ERR_NUM  )
WHERE	USR_ID  = #{usrId, jdbcType=VARCHAR}

/* ====== cmn.login.updateUserPassErrNum =========*/
UPDATE  CMN_USR_MST
SET     PASS_ATMT_NUM = decode( #{loginResult, jdbcType=VARCHAR} , 'SUCCESS', 0, 'WRONG_OTP', NVL(PASS_ATMT_NUM,0) + 1 , PASS_ATMT_NUM  )
WHERE   USR_ID = #{usrId, jdbcType=VARCHAR}

mapper.select:
 	/* lognMapper.getUsrMacAddr */
 	SELECT  A.USR_ID
    		, A.APPL_END_DTTM
        	, A.APPL_STRT_DTTM
        	, A.MAC_ADDR
	FROM    CMN_USR_MAC_ADDR A
	WHERE   A.USR_ID        = #{usrId}
	AND     A.APPL_END_DTTM = '99991231235959'
	AND     A.MAC_ADDR      = #{MAC_ADDR}

/* loginMapper.selectAuthUseYN */
SELECT
  USG_YN
FROM
  CMN_GRP_CD_MST
WHERE
  GRP_ID      = #{grpId}
  AND CD_VAL  = #{cdVal}

mapper.update:
/* ====== cmn.login.updateOtp =========*/
UPDATE CMN_USR_MST
   SET OTP = #{otp}
   	   , PASS_ATMT_NUM = 0
 WHERE USR_ID = #{usrId}

/* ====== cmn.login.updatePassInfo =========*/
UPDATE  CMN_USR_MST
   SET  PASS = #{pass}
        , PASS_ERR_NUM = 0
        , PASS_LAST_RVISN_DT = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
        , PASS_INIT = 'N'
 WHERE  USR_ID = UPPER(#{usrId})
   AND  PASS = #{oldPass}

mapper.select:
/* loginMapper.getUsrMskYn */
SELECT MSK_AUTH_YN
FROM   CMN_USR_MST
WHERE  USR_ID = #{userId}

mapper.update:
/* ====== cmn.login.updateUsrStatusReq =========*/
UPDATE  CMN_USR_MST
SET     STATUS_REQ = 'R',
           RVISN_ID = SUBSTRB(#{usrId, jdbcType=VARCHAR},1,10),   
	 	   RVISN_DTTM = SYSDATE   
WHERE   USR_ID = #{usrId}

